import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const HoroscopePage = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { name, dob } = location.state || {};

  const getZodiacSign = (dateString) => {
    const date = new Date(dateString);
    const month = date.getMonth() + 1;
    const day = date.getDate();

    if ((month === 3 && day >= 21) || (month === 4 && day <= 19)) return 'Aries';
    if ((month === 4 && day >= 20) || (month === 5 && day <= 20)) return 'Taurus';
    if ((month === 5 && day >= 21) || (month === 6 && day <= 20)) return 'Gemini';
    if ((month === 6 && day >= 21) || (month === 7 && day <= 22)) return 'Cancer';
    if ((month === 7 && day >= 23) || (month === 8 && day <= 22)) return 'Leo';
    if ((month === 8 && day >= 23) || (month === 9 && day <= 22)) return 'Virgo';
    if ((month === 9 && day >= 23) || (month === 10 && day <= 22)) return 'Libra';
    if ((month === 10 && day >= 23) || (month === 11 && day <= 21)) return 'Scorpio';
    if ((month === 11 && day >= 22) || (month === 12 && day <= 21)) return 'Sagittarius';
    if ((month === 12 && day >= 22) || (month === 1 && day <= 19)) return 'Capricorn';
    if ((month === 1 && day >= 20) || (month === 2 && day <= 18)) return 'Aquarius';
    if ((month === 2 && day >= 19) || (month === 3 && day <= 20)) return 'Pisces';
    return 'Aries';
  };

  const horoscopes = {
    Aries: "The stars align for new beginnings. Your fiery energy will lead to exciting opportunities.",
    Taurus: "Stability and growth are in your future. Trust your instincts in financial matters.",
    Gemini: "Communication brings unexpected rewards. Your curiosity opens new doors.",
    Cancer: "Emotional connections deepen. Home and family bring joy and comfort.",
    Leo: "Your natural leadership shines bright. Creative projects flourish under your guidance.",
    Virgo: "Attention to detail pays off. Health and wellness take center stage.",
    Libra: "Balance and harmony guide your path. Relationships reach new levels of understanding.",
    Scorpio: "Transformation is your superpower. Deep insights reveal hidden truths.",
    Sagittarius: "Adventure calls your name. Expand your horizons through learning and travel.",
    Capricorn: "Your hard work bears fruit. Success comes through persistence and dedication.",
    Aquarius: "Innovation and friendship light your way. Unique ideas gain recognition.",
    Pisces: "Intuition is your guide. Creative and spiritual pursuits bring fulfillment."
  };

  const zodiacSign = getZodiacSign(dob);
  const horoscope = horoscopes[zodiacSign];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-600 via-purple-600 to-blue-800 relative overflow-hidden">
      {/* Watermark Doodles */}
      <div className="absolute inset-0 opacity-10 pointer-events-none">
        <div className="absolute top-10 left-10 text-6xl animate-float">🔮</div>
        <div className="absolute top-20 right-20 text-5xl animate-float" style={{animationDelay: '1s'}}>🪄</div>
        <div className="absolute bottom-20 left-20 text-4xl animate-float" style={{animationDelay: '2s'}}>⭐</div>
        <div className="absolute bottom-10 right-10 text-5xl animate-float" style={{animationDelay: '0.5s'}}>🌙</div>
        <div className="absolute top-1/2 left-5 text-4xl animate-float" style={{animationDelay: '1.5s'}}>✨</div>
        <div className="absolute top-1/3 right-5 text-4xl animate-float" style={{animationDelay: '2.5s'}}>🌟</div>
      </div>

      <div className="flex items-center justify-center min-h-screen p-4">
        <div className="bg-white bg-opacity-20 backdrop-blur-md rounded-3xl p-8 shadow-2xl border border-white border-opacity-30 max-w-2xl w-full">
          <div className="text-center mb-8">
            <h1 className="text-4xl font-bold text-white mb-4">Your Horoscope</h1>
            <div className="text-6xl mb-4">🔮</div>
            <h2 className="text-2xl font-semibold text-white mb-2">Hello, {name}!</h2>
            <p className="text-white text-opacity-90">Born on {new Date(dob).toLocaleDateString()}</p>
          </div>

          <div className="bg-white bg-opacity-10 rounded-2xl p-6 mb-6">
            <div className="text-center mb-4">
              <h3 className="text-3xl font-bold text-white mb-2">{zodiacSign}</h3>
              <div className="text-4xl mb-4">♈♉♊♋♌♍♎♏♐♑♒♓</div>
            </div>
            <p className="text-white text-lg leading-relaxed text-center">
              {horoscope}
            </p>
          </div>

          <div className="text-center">
            <button
              onClick={() => navigate('/')}
              className="bg-gradient-to-r from-purple-500 to-blue-500 hover:from-purple-600 hover:to-blue-600 text-white font-semibold py-3 px-8 rounded-xl transition duration-300 transform hover:scale-105 shadow-lg"
            >
              ← Back to Home
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HoroscopePage;
